export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  // Let's implement actual Game of Life logic now that we have multiple test cases requiring real behavior.
  // We represent living cells using a Set of coordinate strings 'x,y'.
  const liveSet = new Set<string>();
  for (const [x, y] of cells) {
    liveSet.add(`${x},${y}`);
  }

  // Count neighbors around living cells and their dead neighbors.
  const neighborCounts = new Map<string, number>();

  for (const [cx, cy] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dx !== 0 || dy !== 0 ? dy <= 1 : false; dy++) {
        // Wait, the loops can be cleaner or we can just iterate over all 8 neighbors:
      }
    }
  }

  // Let's write the neighbor-counting loop safely:
  const getNeighbors = (x: number, y: number): [number, number][] => {
    return [
      [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
      [x - 1, y],                 [x + 1, y],
      [x - 1, y + 1], [x, y + 1], [x + 1, y + 1]
    ];
  };

  for (const [cx, cy] of cells) {
    for (const [nx, ny] of getNeighbors(cx, cy)) {
      const key = `${nx},${ny}`;
      neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
    }
  }

  const nextLiveCells: Cell[] = [];

  // Rules:
  // 1. Any live cell with 2 or 3 neighbors lives.
  // 2. Any dead cell with exactly 3 neighbors becomes alive.

  // We iterate over all coordinates that have at least one living neighbor.
  for (const [key, count] of neighborCounts.entries()) {
    const isLive = liveSet.has(key);
    if (isLive) {
      if (count === 2 || count === 3) {
        const [x, y] = key.split(",").map(Number);
        nextLiveCells.push([x, y]);
      }
    } else {
      if (count === 3) {
        const [x, y] = key.split(",").map(Number);
        nextLiveCells.push([x, y]);
      }
    }
  }

  return nextLiveCells;
}

